// ── SWARM COORDINATOR v3: Task Classifier + Tier Mapper ───────────────
// Phase 3: also emits swarmTier for Phase 2 LiteLLM routing groups

const body = $input.first().json.body || $input.first().json;
const task = (body.task || body.message || body.prompt || '').trim();
const forceAgent = body.agent || null;
const skipMemory = body.skip_memory || false; // escape hatch

if (!task) {
  throw new Error('No task provided. Send: { "task": "your request here" }');
}

// ── Complexity Classification ─────────────────────────────────────────
const words = task.split(/\s+/).length;
const heavyKeywords = ['architect', 'design', 'build', 'implement', 'refactor',
  'multi-step', 'plan', 'research', 'analyze', 'investigate', 'comprehensive',
  'full', 'complete', 'system', 'create app', 'write app', 'debug'];
const codeKeywords = ['code', 'function', 'script', 'bug', 'error', 'fix',
  'write', 'implement', 'build', 'deploy', 'docker', 'python', 'javascript',
  'bash', 'sql', 'api', 'endpoint', 'class', 'module', 'test'];
const searchKeywords = ['search', 'find', 'look up', 'what is', 'who is',
  'latest', 'news', 'current', 'today', 'web', 'internet', 'google'];

const taskLower = task.toLowerCase();

let complexity = 'medium';
if (words > 60 || heavyKeywords.some(k => taskLower.includes(k))) {
  complexity = 'heavy';
} else if (words < 15) {
  complexity = 'tiny';
}

// ── Agent + Tier Routing ───────────────────────────────────────────────
let agent = 'litellm';
let agentUrl = 'http://litellm:4000';
let agentEndpoint = '/v1/chat/completions';
let model = 'swarm-tiny';
let swarmTier = 'swarm-tiny'; // Phase 2 LiteLLM routing group

if (!forceAgent) {
  if (searchKeywords.some(k => taskLower.includes(k))) {
    agent = 'perplexica';
    agentUrl = 'http://perplexica:3002';
    agentEndpoint = '/api/search';
    model = 'search';
    swarmTier = 'search';
  } else if (codeKeywords.some(k => taskLower.includes(k))) {
    agent = 'openhands';
    agentUrl = 'http://openhands:3003';
    agentEndpoint = '/api/conversations';
    model = 'swarm-code';
    swarmTier = 'swarm-code';
  } else if (complexity === 'heavy') {
    agent = 'litellm';
    model = 'swarm-heavy';
    swarmTier = 'swarm-heavy';
  } else if (complexity === 'medium') {
    agent = 'litellm';
    model = 'swarm-medium';
    swarmTier = 'swarm-medium';
  } else {
    agent = 'litellm';
    model = 'swarm-tiny';
    swarmTier = 'swarm-tiny';
  }
} else {
  agent = forceAgent;
  swarmTier = forceAgent === 'litellm' ? `swarm-${complexity}` : forceAgent;
  model = swarmTier;
}

const taskId = `swarm_${Date.now()}_${Math.random().toString(36).substr(2,6)}`;

return {
  task,
  taskId,
  complexity,
  agent,
  agentUrl,
  agentEndpoint,
  model,
  swarmTier,
  skipMemory,
  timestamp: new Date().toISOString(),
  words
};

// ── Phase 3: Memory Context Injection ───────────────────────────────
// Takes Qdrant search results and builds a context block.
// Prepends it to the task prompt for LiteLLM calls.
// Perplexica + OpenHands receive the raw task — they have their own context.
// If no memories found (first run, empty collection), passes task unchanged.

const routerData = $('Classify & Route Task').first().json;
const searchRaw = $input.first().json;

const memories = (searchRaw.result || []).filter(r => r.score >= 0.65);

let contextBlock = '';
let memoryCount = 0;
let memoryIds = [];

if (memories.length > 0 && !routerData.skipMemory) {
  memoryCount = memories.length;
  memoryIds = memories.map(m => m.id);

  const lines = memories.map((m, i) => {
    const p = m.payload || {};
    return [
      `### Prior Result ${i + 1} (score: ${Math.round(m.score * 100)}% | agent: ${p.agent} | model: ${p.model})`,
      `Task: ${p.task || ''}`,
      `Result: ${(p.result || '').substring(0, 600)}`
    ].join('\n');
  });

  contextBlock = [
    '---',
    'RELEVANT PRIOR KNOWLEDGE (from swarm memory):',
    lines.join('\n\n'),
    '---',
    'Use the above as context if relevant. Do not repeat it verbatim.',
    ''
  ].join('\n');
}

// Build the enriched prompt for LiteLLM (agents get raw task)
const enrichedTask = contextBlock
  ? `${contextBlock}\nCURRENT TASK:\n${routerData.task}`
  : routerData.task;

return {
  ...routerData,
  enrichedTask,
  contextBlock,
  memoryCount,
  memoryIds,
  memoryUsed: memoryCount > 0
};

// Normalize responses from all 3 agents into a standard shape
const routerData = $('Inject Memory Context').first().json;
const raw = $input.first().json;

let result = '';

if (routerData.agent === 'perplexica') {
  result = raw.message || raw.answer || raw.text || JSON.stringify(raw);
} else if (routerData.agent === 'openhands') {
  result = raw.conversation_id
    ? `OpenHands task started. Conversation ID: ${raw.conversation_id}. Monitor: http://localhost:3003`
    : raw.message || JSON.stringify(raw);
} else {
  result = raw.choices?.[0]?.message?.content
    || raw.content || raw.message || JSON.stringify(raw);
}

return {
  taskId:       routerData.taskId,
  task:         routerData.task,
  enrichedTask: routerData.enrichedTask,
  agent:        routerData.agent,
  model:        routerData.swarmTier,
  complexity:   routerData.complexity,
  memoryUsed:   routerData.memoryUsed,
  memoryCount:  routerData.memoryCount,
  result,
  timestamp:    routerData.timestamp,
  completed_at: new Date().toISOString()
};
